patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 842881156dc6..f0ffa3db2d18 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -1860,7 +1860,27 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
         return CastInst::Create(Instruction::ZExt, NarrowMaxMin, II->getType());
       }
     }
-    // If both operands of unsigned min/max are sign-extended, it is still ok
+    // umax(shl nuw X, 1, add X, 1) --> select X == 0, 1, shl nuw X, 1
+    // When X is 0: max(0, 1) = 1
+    // When X >= 1: max(X*2, X+1) = X*2 (since X*2 >= X+1 for X >= 1)
+    Value *ShlSrc;
+    Value *ShlOp = nullptr;
+    if (match(I0, m_NUWShl(m_Value(ShlSrc), m_One())) &&
+        match(I1, m_c_Add(m_Specific(ShlSrc), m_One()))) {
+      ShlOp = I0;
+    } else if (match(I1, m_NUWShl(m_Value(ShlSrc), m_One())) &&
+               match(I0, m_c_Add(m_Specific(ShlSrc), m_One()))) {
+      ShlOp = I1;
+    }
+    if (ShlOp) {
+      Value *Cmp = Builder.CreateICmpEQ(ShlSrc,
+                                        ConstantInt::get(ShlSrc->getType(), 0));
+      SelectInst *SI = SelectInst::Create(Cmp, ConstantInt::get(II->getType(), 1), ShlOp);
+      // Add range attribute: result is always >= 1
+      unsigned BitWidth = II->getType()->getScalarSizeInBits();
+      II->getFunction()->addRangeRetAttr(ConstantRange(APInt(BitWidth, 1), APInt(BitWidth, 0)));
+      return SI;
+    }
     // to narrow the operation.
     [[fallthrough]];
   }

